solution:
.container {
  display: flex;
  flex-wrap: wrap;
  background: #f0f0f0;
}
.item {
  flex: 1 1 150px;
  height: 100px;
  background: #42a5f5;
  color: white;
  display: flex;
  align-items: center;
  justify-content: center;
  border: 2px solid #fff;
  box-sizing: border-box;
}
.item.wide { flex: 2 1 300px; background: #ff9800; }
.item.medium { flex: 1.5 1 225px; background: #4caf50; }
